PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?paper ?paperLabel ?outputType ?outputTypeLabel
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181003 ?nlpTask .
  ?nlpTask orkgp:P181006 ?taskOutput .
  ?taskOutput orkgp:P181007 ?outputType .
  FILTER NOT EXISTS { ?taskOutput orkgp:P181008 ?classificationLabel . }
  FILTER NOT EXISTS { ?taskOutput orkgp:P181009 ?extractedElement . }
  FILTER NOT EXISTS { ?taskOutput orkgp:P181010 ?mappingCardinality . }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?outputType rdfs:label ?outputTypeLabel . }
}
ORDER BY ?paperLabel ?outputTypeLabel

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?taskInput ?taskInputLabel ?mappingCardinality ?mappingCardinalityLabel
       (COUNT(DISTINCT ?paper) AS ?paperCount)
       (GROUP_CONCAT(DISTINCT ?paperLabel; SEPARATOR=" | ") AS ?papers)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181003 ?nlpTask .
  ?nlpTask orkgp:P181005 ?taskInput ;
           orkgp:P181006 ?taskOutput .
  ?taskOutput orkgp:P181010 ?mappingCardinality .
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?taskInput rdfs:label ?taskInputLabel . }
  OPTIONAL { ?mappingCardinality rdfs:label ?mappingCardinalityLabel . }
}
GROUP BY ?taskInput ?taskInputLabel ?mappingCardinality ?mappingCardinalityLabel
HAVING (COUNT(DISTINCT ?paper) >= 2)
ORDER BY DESC(?paperCount) ?taskInputLabel ?mappingCardinalityLabel

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
