PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?paper ?paperLabel ?reportedKind ?reportedValue ?reportedValueLabel
WHERE {
  {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 ;
                  orkgp:P181003 ?nlpTask .
    ?nlpTask orkgp:P181006 ?taskOutput .
    ?taskOutput orkgp:P181008 ?reportedValue .
    FILTER NOT EXISTS { ?taskOutput orkgp:P181009 ?otherValue . }
    BIND("classification_label" AS ?reportedKind)
  }
  UNION
  {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 ;
                  orkgp:P181003 ?nlpTask .
    ?nlpTask orkgp:P181006 ?taskOutput .
    ?taskOutput orkgp:P181009 ?reportedValue .
    FILTER NOT EXISTS { ?taskOutput orkgp:P181008 ?otherValue . }
    BIND("extracted_element" AS ?reportedKind)
  }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?reportedValue rdfs:label ?reportedValueLabel . }
}
ORDER BY ?paperLabel ?reportedKind ?reportedValueLabel

