SELECT ?algorithm ?algorithmLabel ?dependency ?dependencyLabel
       (COUNT(DISTINCT ?approachType) AS ?approachTypeCount)
WHERE {
  ?paper orkgp:P31 ?contribution .
  ?contribution a orkgc:C121001 ;
                orkgp:P181046 ?implementedApproach .
  ?implementedApproach orkgp:P58069 ?algorithm ;
                       orkgp:P181048 ?dependency ;
                       orkgp:P5043 ?approachType .
  OPTIONAL { ?algorithm rdfs:label ?algorithmLabel . }
  OPTIONAL { ?dependency rdfs:label ?dependencyLabel . }
}
GROUP BY ?algorithm ?algorithmLabel ?dependency ?dependencyLabel
