PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?metric ?metricLabel
WHERE {
  ?paper1 orkgp:P31 ?contribution1 .
  ?contribution1 a orkgc:C121001 ;
                 orkgp:HAS_EVALUATION ?evaluation1 .
  ?evaluation1 orkgp:P110006 ?metric ;
               orkgp:P181051 ?baselineComparison .

  ?paper2 orkgp:P31 ?contribution2 .
  ?contribution2 a orkgc:C121001 ;
                 orkgp:HAS_EVALUATION ?evaluation2 .
  ?evaluation2 orkgp:P110006 ?metric .
  FILTER NOT EXISTS { ?evaluation2 orkgp:P181051 ?otherBaselineComparison . }

  OPTIONAL { ?metric rdfs:label ?metricLabel . }
}
ORDER BY ?metricLabel

PREFIX orkgr: <http://orkg.org/orkg/resource/>
