PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?reTask ?reTaskLabel
WHERE {
  ?paper1 orkgp:P31 ?contribution1 .
  ?contribution1 a orkgc:C121001 ;
                 orkgp:P181002 ?reTask ;
                 orkgp:P181011 ?dataset1 .
  ?dataset1 orkgp:P181028 ?datasetLocation1 .
  ?datasetLocation1 orkgp:P1003 ?datasetUrl .

  ?paper2 orkgp:P31 ?contribution2 .
  ?contribution2 a orkgc:C121001 ;
                 orkgp:P181002 ?reTask .
  FILTER NOT EXISTS {
    ?contribution2 orkgp:P181011 ?dataset2 .
    ?dataset2 orkgp:P181028 ?datasetLocation2 .
    ?datasetLocation2 orkgp:P1003 ?otherDatasetUrl .
  }

  OPTIONAL { ?reTask rdfs:label ?reTaskLabel . }
}
ORDER BY ?reTaskLabel

