               orkgp:P181051 ?baselineComparison1 .
  ?baselineComparison1 orkgp:P181053 ?baselineDetail .

  ?paper2 orkgp:P31 ?contribution2 .
  ?contribution2 a orkgc:C121001 ;
                 orkgp:HAS_EVALUATION ?evaluation2 .
  ?evaluation2 orkgp:P181050 ?validationProcedure .
  FILTER NOT EXISTS {
    ?evaluation2 orkgp:P181051 ?baselineComparison2 .
    ?baselineComparison2 orkgp:P181053 ?otherBaselineDetail .
