PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?year ?metric ?metricLabel (COUNT(DISTINCT ?baselineType) AS ?baselineTypeCount)
WHERE {
  ?paper orkgp:P31 ?contribution ;
         orkgp:P29 ?year .
  ?contribution a orkgc:C121001 ;
                orkgp:HAS_EVALUATION ?evaluation .
  ?evaluation orkgp:P110006 ?metric ;
              orkgp:P181051 ?baselineComparison .
  ?baselineComparison orkgp:P181052 ?baselineType .
  OPTIONAL { ?metric rdfs:label ?metricLabel . }
}
GROUP BY ?year ?metric ?metricLabel
HAVING (COUNT(DISTINCT ?baselineType) > 1)
ORDER BY ?year DESC(?baselineTypeCount) ?metricLabel

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?paper ?paperLabel ?reportedKind ?reportedValue ?reportedValueLabel
WHERE {
  {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 ;
                  orkgp:P181031 ?annotationProcess .
    ?annotationProcess orkgp:P181039 ?reportedValue .
    FILTER NOT EXISTS { ?annotationProcess orkgp:P181040 ?fatigueTechnique . }
    BIND("shared_material" AS ?reportedKind)
  }
  UNION
  {
    ?paper orkgp:P31 ?contribution .
    ?contribution a orkgc:C121001 ;
                  orkgp:P181031 ?annotationProcess .
    ?annotationProcess orkgp:P181040 ?reportedValue .
    FILTER NOT EXISTS { ?annotationProcess orkgp:P181039 ?sharedMaterial . }
    BIND("fatigue_mitigation" AS ?reportedKind)
  }
  OPTIONAL { ?paper rdfs:label ?paperLabel . }
  OPTIONAL { ?reportedValue rdfs:label ?reportedValueLabel . }
}
ORDER BY ?paperLabel ?reportedKind ?reportedValueLabel

PREFIX orkgr: <http://orkg.org/orkg/resource/>
PREFIX orkgc: <http://orkg.org/orkg/class/>
PREFIX orkgp: <http://orkg.org/orkg/predicate/>
